    [nomeCurso] NVARCHAR(MAX) NOT NULL,
    [quantPeriodos] INT NOT NULL,
    [codigoUnidadeOrganizacional] NVARCHAR(MAX) NOT NULL,
    [data_criacao] NVARCHAR(MAX) NULL DEFAULT CURRENT_TIMESTAMP,
    [data_atualizacao] NVARCHAR(MAX) NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT PK_imp_001_cursos PRIMARY KEY ([codigoCurso])
);

